import React from "react";
import COLORS from "../../constants/colors";
import FlowTopBar from "../common/FlowTopBar";
import HeartView from "../common/HeartView";
import WordPreviewCard from "../common/WordPreviewCard";
import {
  centerSubStyle,
  heroWordStyle,
  mainCardStyle,
  pageStyle,
} from "../../styles/commonStyles";
import { speakFrench } from "../../utils/speech";

export default function LearnPhaseOne({
  word,
  progressText,
  heartCount,
  options,
  triedOptions = [],
  onChooseOption,
  onOpenDetail,
  onPrev,
  onStar,
  onSkip,
  onHome,
  disablePrev = false,
}) {
  if (!word) return null;

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        {/* 顶部导航 */}
        <FlowTopBar
          title={`学习进度：${progressText}`}
          onPrev={onPrev}
          onStar={onStar}
          onSkip={onSkip}
          onHome={onHome}
          disablePrev={disablePrev}
        />

        {/* 爱心 */}
        <div style={{ display: "flex", justifyContent: "center", marginBottom: "0.3rem" }}>
          <HeartView count={heartCount} />
        </div>

        {/* 单词 + 发音 */}
        <div style={heroWordStyle()} onClick={() => speakFrench(word.word)}>
          {word.word}
        </div>
        <div
          style={{ ...centerSubStyle(), cursor: "pointer" }}
          onClick={() => speakFrench(word.word)}
        >
          {word.phonetic} 🔊
        </div>

        {/* 汉语选项 */}
        <div style={{ display: "grid", gap: "0.8rem", marginTop: "1.4rem" }}>
          {options.map((opt, i) => {
            const selected = triedOptions.includes(opt);
            const isCorrect = opt === word.translation;

            // ⭐ 核心：找到“该汉语对应的法语”
            const selectedFrench =
              word.allTranslations?.find((t) => t.cn === opt)?.fr;

            return (
              <div key={i}>
                <button
                  onClick={() => onChooseOption(opt)}
                  style={{
                    width: "100%",
                    padding: "1rem",
                    borderRadius: "14px",
                    border: `1px solid ${
                      selected ? (isCorrect ? COLORS.green : COLORS.red) : COLORS.line
                    }`,
                    background: selected
                      ? isCorrect
                        ? COLORS.paleGreen
                        : COLORS.palePink
                      : "#FBFBFD",
                    color: COLORS.text,
                    textAlign: "left",
                    fontSize: "1rem",
                    cursor: "pointer",
                  }}
                >
                  <strong style={{ marginRight: "0.45rem", color: COLORS.blue }}>
                    {word.type}
                  </strong>
                  {opt}
                </button>

                {/* ✅ 选对：保持原逻辑 */}
                {selected && isCorrect && (
                  <WordPreviewCard word={word} onDetail={onOpenDetail} />
                )}

                {/* ✅ 选错：显示“你选的汉语 → 对应法语” */}
                {selected && !isCorrect && (
                  <WordPreviewCard
                    word={{
                      ...word,
                      word: selectedFrench || "（未找到对应法语）",
                      translation: opt,
                    }}
                    onDetail={onOpenDetail}
                  />
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}