export function markSpellingWrong(state, wordId) {
  const progress = getWordProgress(state, wordId);

  return setWordProgress(state, wordId, {
    ...progress,
    spellingWrongCount: (progress.spellingWrongCount || 0) + 1,
    totalWrongCount: (progress.totalWrongCount || 0) + 1,
    wrongTypes: [...(progress.wrongTypes || []), "拼写错误"],
  });
}