import React, { useState } from "react";

export default function ReviewPhaseOne({
  word,
  progressText,
  heartCount,
  onKnown,
  onPrev,
  onStar,
  onSkip,
  onHome,
}) {
  const [selected, setSelected] = useState(null);

  // ✅ 更稳定图片源（替换掉 source.unsplash）
  const getImage = () =>
    `https://images.unsplash.com/photo-1502602898657-3e91760cbb34?auto=format&fit=crop&w=800&q=80`;

  const handleClick = () => {
    if (selected) return;
    setSelected(true);

    setTimeout(() => {
      onKnown();
    }, 1000);
  };

  return (
    <div style={styles.wrapper}>
      <div style={styles.card}>
        {/* 顶部 */}
        <div style={styles.header}>
          <span>{progressText}</span>
          <span>❤️ {heartCount}</span>
        </div>

        {/* 单词 */}
        <h1 style={styles.word}>{word.word}</h1>

        {/* ✅ 图片（带兜底） */}
        <div style={styles.imageWrapper}>
          <img
            src={getImage()}
            alt=""
            style={styles.image}
            onError={(e) => {
              e.target.src =
                "https://images.unsplash.com/photo-1492724441997-5dc865305da7";
            }}
          />
        </div>

        {/* 例句 */}
        <div style={styles.example}>{word.example}</div>

        {/* 按钮 */}
        <div style={styles.btns}>
          <button
            style={{
              ...styles.btn,
              background: selected ? "#ffd6a5" : "#fff3e6",
            }}
            onClick={handleClick}
          >
            认识
          </button>

          <button style={styles.btn} onClick={handleClick}>
            不认识
          </button>
        </div>
      </div>
    </div>
  );
}

const styles = {
  wrapper: {
    minHeight: "100vh",
    background: "linear-gradient(135deg,#ffecd2,#fcb69f)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  card: {
    width: 380,
    background: "#fff",
    borderRadius: 24,
    padding: 24,
    boxShadow: "0 20px 40px rgba(0,0,0,0.15)",
    textAlign: "center",
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    color: "#999",
    marginBottom: 10,
  },

  word: {
    fontSize: 36,
    fontWeight: "bold",
    marginBottom: 12,
  },

  imageWrapper: {
    marginBottom: 16,
    borderRadius: 16,
    overflow: "hidden",
  },

  image: {
    width: "100%",
    height: 180,
    objectFit: "cover",
    transition: "transform 0.3s",
  },

  example: {
    background: "#fff7f0",
    padding: 12,
    borderRadius: 12,
    marginBottom: 20,
    color: "#555",
  },

  btns: {
    display: "flex",
    gap: 10,
  },

  btn: {
    flex: 1,
    padding: 14,
    borderRadius: 14,
    border: "none",
    background: "#fff3e6",
    cursor: "pointer",
    fontWeight: "bold",
  },
};