import React from "react";
import {
  bottomNavBtnStyle,
  bottomNavStyle,
} from "../../styles/commonStyles";

export default function HomeBottomNav({
  currentScreen,
  onGoMyContent,
  onGoStatistics,
}) {
  return (
    <div style={bottomNavStyle()}>
      <button
        onClick={onGoMyContent}
        style={bottomNavBtnStyle(currentScreen === "myContent")}
      >
        📚
        <div>我的内容</div>
      </button>

      <button
        onClick={onGoStatistics}
        style={bottomNavBtnStyle(currentScreen === "statistics")}
      >
        📈
        <div>学习情况</div>
      </button>
    </div>
  );
}