// 名称映射：关键词严格匹配地标名称 → 对应正确ID的资源
const LANDMARK_NAME_MAP = [
  { keywords: ["蒙马特", "圣心堂", "montmartre"], resource: LANDMARK_RESOURCES[1] },
  { keywords: ["塞纳", "seine"], resource: LANDMARK_RESOURCES[2] },
  { keywords: ["圣母院", "notre"], resource: LANDMARK_RESOURCES[3] },
  { keywords: ["卢浮宫", "louvre"], resource: LANDMARK_RESOURCES[4] },
  { keywords: ["凡尔赛", "versailles"], resource: LANDMARK_RESOURCES[5] },
  { keywords: ["香榭丽舍", "champselysees"], resource: LANDMARK_RESOURCES[6] },
  { keywords: ["埃菲尔", "铁塔", "eiffel"], resource: LANDMARK_RESOURCES[7] },
  { keywords: ["巴黎", "全景", "终章"], resource: LANDMARK_RESOURCES[8] },
];

export function getLandmarkResource(landmark) {
  if (!landmark) {
    return { video: "", bgImage: DEFAULT_BG_IMAGE, videoPoster: DEFAULT_BG_IMAGE };
  }

  // 优先按ID匹配（最可靠）
  if (landmark.id !== undefined && LANDMARK_RESOURCES[landmark.id]) {
    return {
      video: "",
      videoPoster: DEFAULT_BG_IMAGE,
      ...LANDMARK_RESOURCES[landmark.id], // 覆盖默认值
    };
  }

  // 备用：按名称匹配
  const name = String(landmark.name || "").toLowerCase();
  const matched = LANDMARK_NAME_MAP.find((item) =>
    item.keywords.some((kw) => name.includes(kw.toLowerCase()))
  );

  if (matched?.resource) {
    return {
      video: "",
      videoPoster: DEFAULT_BG_IMAGE,
      ...matched.resource,
    };
  }

  // 兜底
  return { video: "", bgImage: DEFAULT_BG_IMAGE, videoPoster: DEFAULT_BG_IMAGE };
}