import React, { useState, useMemo } from "react";
import COLORS from "../../constants/colors";
import {
  contentSectionStyle,
  listCardStyle,
  mainCardStyle,
  pageStyle,
  sectionTitleStyle,
  smallTopBtnStyle,
} from "../../styles/commonStyles";

export default function StatisticsPage({
  state,
  statsForCurve,
  onGoHome,
  // 星标单词相关 props
  starredWords = [],
  showTempMessage = () => {},
  openWordDetail = () => {},
  speakFrench = () => {},
  // 新增：遗忘曲线功能所需 props
  allWords = [],
  getWordProgress,
  getToday,
  addDays,
  diffDays,
}) {
  // 容错处理：避免数组为空时 Math.max 报错
  const maxCurve = statsForCurve.length > 0 
    ? Math.max(...statsForCurve.map((x) => x.count), 1) 
    : 1;

  // 处理学习历史数据（兼容数据为空的情况）
  const learnedHistory = Array.isArray(state.user.learnedHistory) 
    ? state.user.learnedHistory.slice(-7) 
    : [];
  const reviewHistory = Array.isArray(state.user.reviewHistory) 
    ? state.user.reviewHistory.slice(-7) 
    : [];
  const spellingHistory = Array.isArray(state.user.spellingHistory) 
    ? state.user.spellingHistory.slice(-7) 
    : [];

  // 提取所有日期并排序
  const allDates = Array.from(
    new Set([
      ...learnedHistory.map((x) => x.date),
      ...reviewHistory.map((x) => x.date),
      ...spellingHistory.map((x) => x.date),
    ])
  ).sort();

  // 计算累计学习数据
  const totalLearn = learnedHistory.reduce((sum, x) => sum + (x.count || 0), 0);
  const totalReview = reviewHistory.reduce((sum, x) => sum + (x.count || 0), 0);
  const totalSpelling = spellingHistory.reduce((sum, x) => sum + (x.count || 0), 0);

  // 新增：状态管理 - 控制遗忘曲线单词列表的显示/隐藏
  const [activeCurveLabel, setActiveCurveLabel] = useState(null);
  const [curveWords, setCurveWords] = useState([]);

  // 点击统计项的交互提示（增强版）
  const handleStatClick = (type, value, label = "") => {
    const messages = {
      learn: `累计学习 ${value} 个单词`,
      review: `累计复习 ${value} 个单词`,
      spelling: `累计拼写 ${value} 个单词`,
      checkin: `连续签到 ${value} 天`,
      energy: `当前能量值 ${value}`,
      starred: `星标单词 ${value} 个`,
      curve: `该分类下有 ${value} 个单词待复习`
    };
    showTempMessage(messages[type] || "查看详情", 1500);

    // 新增：如果是点击遗忘曲线项，计算并显示对应单词
    if (type === "curve" && value > 0) {
      calculateCurveWords(label);
      setActiveCurveLabel(label);
    } else if (type === "curve" && value === 0) {
      showTempMessage(`该分类下暂无待复习单词`, 1500);
      setActiveCurveLabel(null);
      setCurveWords([]);
    }
  };

  // 新增：根据遗忘曲线分类计算对应的单词列表
  const calculateCurveWords = (label) => {
    const today = getToday();
    const words = [];

    allWords.forEach((word) => {
      const p = getWordProgress(state, word.id);
      if (!p.reviewDue) return;
      
      const dayDiff = diffDays(p.reviewDue, today);
      let wordLabel = "";

      if (dayDiff <= 0) wordLabel = "今日到期";
      else if (dayDiff === 1) wordLabel = "1天后";
      else if (dayDiff <= 4) wordLabel = "2-4天";
      else if (dayDiff <= 7) wordLabel = "5-7天";
      else wordLabel = "8天+";

      if (wordLabel === label) {
        words.push({
          ...word,
          dueDate: p.reviewDue,
          dueInDays: dayDiff < 0 ? "已逾期" : `${dayDiff}天`,
        });
      }
    });

    setCurveWords(words);
  };

  // 新增：关闭遗忘曲线单词列表
  const closeCurveWords = () => {
    setActiveCurveLabel(null);
    setCurveWords([]);
  };

  // 点击星标单词/遗忘曲线单词播放发音
  const handleSpeakWord = (word, e) => {
    e.stopPropagation(); // 阻止事件冒泡
    speakFrench(word);
    showTempMessage(`🔊 播放发音: ${word}`, 1000);
  };

  return (
    <div style={pageStyle()}>
      <div style={mainCardStyle()}>
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "1rem",
          }}
        >
          <div
            style={{
              fontSize: "1.35rem",
              fontWeight: 800,
              color: COLORS.text,
            }}
          >
            学习情况
          </div>

          <button 
            onClick={() => {
              showTempMessage("返回主页", 1000);
              onGoHome();
            }} 
            style={smallTopBtnStyle("#E9EEF5")}
          >
            ⌂
          </button>
        </div>

        {/* 1. 艾宾浩斯遗忘曲线（增强版） */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>1. 艾宾浩斯遗忘曲线 </div>
          <div style={{ color: COLORS.subtext, marginBottom: "1rem" }}>
            根据当前到期日粗略呈现你的复习压力分布（点击查看具体单词）
          </div>

          <div style={{ display: "grid", gap: "0.9rem" }}>
            {statsForCurve.map((item) => (
              <div 
                key={item.label}
                style={{ 
                  cursor: "pointer",
                  // 选中状态高亮
                  backgroundColor: activeCurveLabel === item.label ? "#f0f7ff" : "transparent",
                  padding: "0.5rem",
                  borderRadius: "8px",
                  transition: "background-color 0.2s ease"
                }}
                onClick={() => handleStatClick("curve", item.count, item.label)}
                onMouseEnter={(e) => {
                  if (activeCurveLabel !== item.label) {
                    e.currentTarget.style.backgroundColor = "#f8f9fa";
                  }
                }}
                onMouseLeave={(e) => {
                  if (activeCurveLabel !== item.label) {
                    e.currentTarget.style.backgroundColor = "transparent";
                  }
                }}
              >
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginBottom: "0.3rem",
                  }}
                >
                  <span style={{ color: COLORS.text, fontWeight: item.count > 0 ? 700 : 400 }}>
                    {item.label}
                  </span>
                  <span style={{ 
                    color: item.count > 0 ? COLORS.blue : COLORS.subtext,
                    fontWeight: 700
                  }}>
                    {item.count}
                  </span>
                </div>

                <div
                  style={{
                    height: "10px",
                    background: "#EEF1F4",
                    borderRadius: "999px",
                    overflow: "hidden",
                    transition: "all 0.2s ease",
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "#E5E9F0";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "#EEF1F4";
                  }}
                >
                  <div
                    style={{
                      width: `${(item.count / maxCurve) * 100}%`,
                      height: "100%",
                      background: `linear-gradient(90deg, ${COLORS.blue}, ${COLORS.gold})`,
                      transition: "width 0.3s ease",
                    }}
                  />
                </div>
              </div>
            ))}
          </div>

          {/* 新增：遗忘曲线对应的单词列表 */}
          {activeCurveLabel && curveWords.length > 0 && (
            <div style={{ 
              marginTop: "1rem",
              padding: "1rem",
              background: "#f8f9fa",
              borderRadius: "12px",
              maxHeight: "300px",
              overflowY: "auto"
            }}>
              <div style={{ 
                display: "flex", 
                justifyContent: "space-between", 
                alignItems: "center",
                marginBottom: "0.8rem",
                borderBottom: `1px solid ${COLORS.line}`,
                paddingBottom: "0.5rem"
              }}>
                <h4 style={{ 
                  margin: 0, 
                  color: COLORS.text,
                  fontSize: "1rem"
                }}>
                  {activeCurveLabel} 待复习单词 ({curveWords.length})
                </h4>
                <button
                  style={{
                    background: "transparent",
                    border: "none",
                    cursor: "pointer",
                    color: COLORS.subtext,
                    fontSize: "1.2rem",
                    padding: "0.2rem",
                  }}
                  onClick={closeCurveWords}
                  aria-label="关闭单词列表"
                >
                  ✕
                </button>
              </div>

              <div style={{ display: "grid", gap: "0.8rem" }}>
                {curveWords.map((word) => (
                  <div 
                    key={word.id}
                    style={{
                      ...listCardStyle(),
                      cursor: "pointer",
                      transition: "all 0.2s ease",
                      display: "flex",
                      justifyContent: "space-between",
                      alignItems: "center",
                      background: "#fff"
                    }}
                    onClick={() => {
                      showTempMessage(`查看单词详情：${word.word}`, 1000);
                      openWordDetail(word.id, { type: "statistics", stage: "curve" });
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.1)";
                      e.currentTarget.style.transform = "translateY(-2px)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.boxShadow = "none";
                      e.currentTarget.style.transform = "translateY(0)";
                    }}
                  >
                    <div style={{ flex: 1 }}>
                      <div style={{ 
                        fontWeight: 700, 
                        color: COLORS.text,
                        fontSize: "1.1rem"
                      }}>
                        {word.word}
                      </div>
                      <div style={{ 
                        color: COLORS.subtext, 
                        marginTop: "0.2rem",
                        fontSize: "0.9rem",
                        display: "flex",
                        justifyContent: "space-between"
                      }}>
                        <span>{word.translation}</span>
                        <span style={{ 
                          color: word.dueInDays === "已逾期" ? "#e53e3e" : COLORS.gold,
                          fontSize: "0.8rem"
                        }}>
                          到期：{word.dueInDays}
                        </span>
                      </div>
                      {word.pronunciation && (
                        <div style={{ 
                          color: COLORS.blue, 
                          fontSize: "0.8rem",
                          marginTop: "0.1rem"
                        }}>
                          /{word.pronunciation}/
                        </div>
                      )}
                    </div>
                    
                    <button
                      style={{
                        background: "transparent",
                        border: "none",
                        cursor: "pointer",
                        color: COLORS.gold,
                        fontSize: "1.2rem",
                        padding: "0.5rem",
                        borderRadius: "50%",
                        transition: "background 0.2s ease"
                      }}
                      onClick={(e) => handleSpeakWord(word.word, e)}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = "#f0f4ff";
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = "transparent";
                      }}
                      aria-label={`播放${word.word}的发音`}
                    >
                      🔊
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>

        {/* 2. 每天的学习情况（保持不变） */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>2. 每天的学习情况</div>
          <div 
            style={{ marginBottom: "0.8rem", color: COLORS.subtext, cursor: "pointer" }}
            onClick={() => {
              handleStatClick("learn", totalLearn);
              handleStatClick("review", totalReview);
              handleStatClick("spelling", totalSpelling);
            }}
          >
            累计学习：{totalLearn} · 累计复习：{totalReview} · 累计拼写：{totalSpelling}
          </div>

          <div style={{ display: "grid", gap: "0.8rem" }}>
            {allDates.length === 0 ? (
              <div style={{ color: COLORS.subtext }}>暂无学习数据</div>
            ) : (
              allDates.map((date) => {
                const learnCount = learnedHistory.find((x) => x.date === date)?.count || 0;
                const reviewCount = reviewHistory.find((x) => x.date === date)?.count || 0;
                const spellingCount =
                  spellingHistory.find((x) => x.date === date)?.count || 0;

                return (
                  <div 
                    key={date} 
                    style={{
                      ...listCardStyle(),
                      cursor: "pointer",
                      transition: "box-shadow 0.2s ease"
                    }}
                    onClick={() => {
                      showTempMessage(`${date}：学习${learnCount} · 复习${reviewCount} · 拼写${spellingCount}`, 2000);
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.boxShadow = "none";
                    }}
                  >
                    <div>
                      <div style={{ fontWeight: 700, color: COLORS.text }}>{date}</div>
                      <div
                        style={{
                          color: COLORS.subtext,
                          marginTop: "0.2rem",
                          lineHeight: 1.6,
                        }}
                      >
                        单词学习：{learnCount} · 复习：{reviewCount} · 拼写：{spellingCount}
                      </div>
                    </div>

                    <div style={{ color: COLORS.blue, fontWeight: 700 }}>
                      {learnCount + reviewCount + spellingCount}
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </section>

        {/* 3. 当前学习状态概览（保持不变） */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>3. 当前学习状态概览</div>

          <div style={{ display: "grid", gap: "0.8rem" }}>
            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease"
              }}
              onClick={() => handleStatClick("checkin", state.user.streak)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>累计签到</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem" }}>
                  当前连续签到天数
                </div>
              </div>
              <div style={{ color: COLORS.blue, fontWeight: 800, fontSize: "1.1rem" }}>
                {state.user.streak}
              </div>
            </div>

            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease"
              }}
              onClick={() => handleStatClick("energy", state.user.energy)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>当前能量值</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem" }}>
                  用于解锁巴黎地图场景
                </div>
              </div>
              <div style={{ color: COLORS.blue, fontWeight: 800, fontSize: "1.1rem" }}>
                ★{state.user.energy}
              </div>
            </div>

            <div 
              style={{
                ...listCardStyle(),
                cursor: "pointer",
                transition: "box-shadow 0.2s ease"
              }}
              onClick={() => handleStatClick("starred", state.user.starredWordIds.length)}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.08)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div>
                <div style={{ fontWeight: 700, color: COLORS.text }}>星标单词数</div>
                <div style={{ color: COLORS.subtext, marginTop: "0.25rem" }}>
                  已加入单词本的重点词汇
                </div>
              </div>
              <div style={{ color: COLORS.gold, fontWeight: 800, fontSize: "1.1rem" }}>
                {state.user.starredWordIds.length}
              </div>
            </div>
          </div>
        </section>

        {/* 4. 星标单词列表（保持不变） */}
        <section style={contentSectionStyle()}>
          <div style={sectionTitleStyle()}>4. 我的星标单词</div>
          <div style={{ color: COLORS.subtext, marginBottom: "1rem" }}>
            点击单词查看详情，点击喇叭图标播放发音
          </div>

          {starredWords.length === 0 ? (
            <div style={{ 
              color: COLORS.subtext, 
              textAlign: "center", 
              padding: "2rem 0",
              borderRadius: "12px",
              background: "#f8f9fa"
            }}>
              📖 暂无星标单词<br />
              学习过程中点击⭐可收藏重点单词
            </div>
          ) : (
            <div style={{ 
              display: "grid", 
              gap: "0.8rem",
              maxHeight: "400px",
              overflowY: "auto",
              paddingRight: "0.5rem"
            }}>
              {starredWords.map((word) => (
                <div 
                  key={word.id}
                  style={{
                    ...listCardStyle(),
                    cursor: "pointer",
                    transition: "all 0.2s ease",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center"
                  }}
                  onClick={() => {
                    showTempMessage(`查看单词详情：${word.word}`, 1000);
                    openWordDetail(word.id, { type: "statistics", stage: "starred" });
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.boxShadow = "0 2px 12px rgba(0,0,0,0.1)";
                    e.currentTarget.style.transform = "translateY(-2px)";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.boxShadow = "none";
                    e.currentTarget.style.transform = "translateY(0)";
                  }}
                >
                  <div style={{ flex: 1 }}>
                    <div style={{ 
                      fontWeight: 700, 
                      color: COLORS.text,
                      fontSize: "1.1rem"
                    }}>
                      {word.word}
                    </div>
                    <div style={{ 
                      color: COLORS.subtext, 
                      marginTop: "0.2rem",
                      fontSize: "0.9rem"
                    }}>
                      {word.translation}
                    </div>
                    {word.pronunciation && (
                      <div style={{ 
                        color: COLORS.blue, 
                        fontSize: "0.8rem",
                        marginTop: "0.1rem"
                      }}>
                        /{word.pronunciation}/
                      </div>
                    )}
                  </div>
                  
                  <button
                    style={{
                      background: "transparent",
                      border: "none",
                      cursor: "pointer",
                      color: COLORS.gold,
                      fontSize: "1.2rem",
                      padding: "0.5rem",
                      borderRadius: "50%",
                      transition: "background 0.2s ease"
                    }}
                    onClick={(e) => handleSpeakWord(word.word, e)}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = "#f0f4ff";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = "transparent";
                    }}
                    aria-label={`播放${word.word}的发音`}
                  >
                    🔊
                  </button>
                </div>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}