import React from "react";
import COLORS from "../../constants/colors";
import TopHeaderInfo from "../common/TopHeaderInfo";
import {
  homeTitleWrapStyle,
  topInfoBarStyle,
} from "../../styles/commonStyles";

export default function HomeTopSection({
  dateText,
  weekdayText,
  weather,
}) {
  return (
    <div style={topInfoBarStyle()}>
      <TopHeaderInfo
        dateText={dateText}
        weekdayText={weekdayText}
        weather={weather}
      />

      <div style={{ flex: 1 }}>
        <div style={homeTitleWrapStyle()}>
          <div
            style={{
              fontSize: "2rem",
              fontWeight: 800,
              color: COLORS.text,
            }}
          >
            🇫🇷 Mon Paris Français
          </div>
          <div
            style={{
              color: COLORS.subtext,
              marginTop: "0.5rem",
            }}
          >
            法式优雅地记住每一个单词
          </div>
        </div>
      </div>

      <div style={{ width: "160px" }} />
    </div>
  );
}