import React from "react";
import COLORS from "../../constants/colors";

export default function TopHeaderInfo({
  dateText,
  weekdayText,
  weather,
}) {
  return (
    <div
      style={{
        display: "inline-flex",
        flexDirection: "column",
        gap: "0.28rem",
        background: "rgba(255,255,255,0.78)",
        border: "1px solid #E7ECF2",
        borderRadius: "16px",
        padding: "0.7rem 0.9rem",
        boxShadow: "0 8px 18px rgba(108,145,191,0.08)",
        minWidth: "160px",
      }}
    >
      <div
        style={{
          color: COLORS.text,
          fontWeight: 800,
          fontSize: "0.98rem",
          lineHeight: 1.3,
        }}
      >
        {dateText || "--"}
      </div>

      <div
        style={{
          color: COLORS.subtext,
          fontSize: "0.88rem",
          lineHeight: 1.4,
        }}
      >
        {weekdayText || ""}
      </div>

      <div
        style={{
          color: COLORS.text,
          fontSize: "0.92rem",
          fontWeight: 600,
          lineHeight: 1.4,
          display: "flex",
          alignItems: "center",
          gap: "0.35rem",
          marginTop: "0.08rem",
        }}
      >
        <span>{weather?.icon || "⛅"}</span>
        <span>
          {weather?.text || "天气加载中"}
          {weather?.temperature !== undefined &&
          weather?.temperature !== null &&
          weather?.temperature !== "--"
            ? ` ${Math.round(weather.temperature)}°C`
            : ""}
        </span>
      </div>
    </div>
  );
}