import React from "react";
import COLORS from "../../constants/colors";

export default function WordPreviewCard({ word, onDetail }) {
  if (!word) return null;

  return (
    <div
      style={{
        background: COLORS.white,
        borderRadius: "16px",
        padding: "0.85rem 1rem",
        boxShadow: "0 8px 20px rgba(108,145,191,0.08)",
        border: `1px solid ${COLORS.line}`,
        marginTop: "0.5rem",
      }}
    >
      <div
        style={{
          fontWeight: 700,
          color: COLORS.text,
          fontSize: "1.02rem",
        }}
      >
        {word.word}
      </div>

      <div
        style={{
          color: COLORS.subtext,
          fontSize: "0.92rem",
          marginTop: "0.2rem",
        }}
      >
        {word.type} · {word.translation}
      </div>

      <div
        onClick={onDetail}
        style={{
          marginTop: "0.65rem",
          borderTop: "1px solid #F0F0F0",
          paddingTop: "0.55rem",
          color: "#111",
          opacity: 0.75,
          cursor: "pointer",
          fontSize: "0.88rem",
        }}
      >
        查看详细释义
      </div>
    </div>
  );
}