import React, { useEffect, useMemo, useState, useRef, useCallback } from "react";
import Particles from "react-tsparticles";
import { loadFull } from "tsparticles";

import { mainCardStyle, pageStyle, primaryBtnStyle } from "../../styles/commonStyles";
import HomeTopSection from "./HomeTopSection";
import LandmarkMapCard from "./LandmarkMapCard";
import CheckInCard from "./CheckInCard";
import HomeActionPanel from "./HomeActionPanel";
import HomeBottomNav from "./HomeBottomNav";
import LandmarkUnlockModal from "./LandmarkUnlockModal";
import InfoMessage from "../common/InfoMessage";
import COLORS from "../../constants/colors";
import {
  DEFAULT_BG_IMAGE,
  getLandmarkResource,
} from "../../constants/landmarkResources";

const BG_STORAGE_KEY = "homepage_selected_landmark_bg_id";

// 核心：通用悬浮放大样式（适配图标/按钮）
const hoverScaleStyle = {
  transition: "transform 0.2s ease, box-shadow 0.2s ease",
  transform: "scale(1)",
  // 修复：内联样式不支持 :hover 伪类，改为通过类名 + CSS 实现
  // 这里先定义基础过渡属性，具体 hover 效果通过 className 关联 global.css
  cursor: "pointer",
};

// 图标专用悬浮样式（放大比例更大）
const iconHoverStyle = {
  ...hoverScaleStyle,
  transform: "scale(1)",
  transition: "transform 0.15s ease-in-out, box-shadow 0.15s ease-in-out",
};

export default function HomePage({
  state,
  currentLandmark,
  landmarks,
  message,
  onShowMessage,
  onCheckIn,
  onStartLearn,
  onStartReview,
  onGoMyContent,
  onGoStatistics,
  onCloseLandmarkUnlock,
  onDailyPlanChange,
}) {
  const particlesInit = useCallback(async (main) => {
    await loadFull(main);
  }, []);

  const particlesOptions = useMemo(
    () => ({
      fullScreen: { enable: false },
      background: {
        color: { value: "transparent" },
      },
      fpsLimit: 60,
      interactivity: {
        events: {
          onClick: { enable: true, mode: "push" },
          onHover: { enable: true, mode: "grab" },
          resize: true,
        },
        modes: {
          push: { quantity: 3 },
          grab: { distance: 150 },
        },
      },
      particles: {
        color: { value: "#1976d2" },
        links: {
          color: "#1976d2",
          distance: 150,
          enable: true,
          opacity: 0.32,
          width: 1,
        },
        move: {
          direction: "none",
          enable: true,
          outModes: { default: "bounce" },
          speed: 2,
        },
        number: {
          density: { enable: true, area: 800 },
          value: 40,
        },
        opacity: { value: 0.5 },
        shape: { type: "circle" },
        size: { value: { min: 1, max: 3 } },
      },
      detectRetina: true,
    }),
    []
  );

  const [selectedLandmarkId, setSelectedLandmarkId] = useState(() => {
    try {
      return (
        window.localStorage.getItem(BG_STORAGE_KEY) ||
        currentLandmark?.id ||
        landmarks?.[0]?.id ||
        1
      );
    } catch {
      return currentLandmark?.id || landmarks?.[0]?.id || 1;
    }
  });

  const [activeBgImage, setActiveBgImage] = useState(DEFAULT_BG_IMAGE);
  const [pendingVideoLandmark, setPendingVideoLandmark] = useState(null);
  const [videoError, setVideoError] = useState(false);
  const videoRef = useRef(null);
  const [preloadedVideo, setPreloadedVideo] = useState(null);

  const energy = Number(state?.user?.energy || 0);

  const selectedLandmark = useMemo(() => {
    return (
      landmarks?.find((item) => String(item.id) === String(selectedLandmarkId)) ||
      currentLandmark ||
      landmarks?.[0] ||
      null
    );
  }, [landmarks, selectedLandmarkId, currentLandmark]);

  useEffect(() => {
    const res = getLandmarkResource(selectedLandmark);
    if (res?.video) {
      setPreloadedVideo(res.video);
    }
  }, [selectedLandmark]);

  useEffect(() => {
    const resource = getLandmarkResource(selectedLandmark);
    setActiveBgImage(resource?.bgImage || DEFAULT_BG_IMAGE);
  }, [selectedLandmark]);

  useEffect(() => {
    try {
      const saved = window.localStorage.getItem(BG_STORAGE_KEY);
      if (!saved && currentLandmark?.id) {
        setSelectedLandmarkId(currentLandmark.id);
      }
    } catch {
      if (currentLandmark?.id) {
        setSelectedLandmarkId(currentLandmark.id);
      }
    }
  }, [currentLandmark]);

  const applyLandmarkBackground = (landmark) => {
    if (!landmark) return;
    setSelectedLandmarkId(landmark.id);
    try {
      window.localStorage.setItem(BG_STORAGE_KEY, String(landmark.id));
    } catch {}
    onShowMessage?.(`已进入【${landmark.name}】地图`);
  };

  const handleLandmarkClick = (landmark) => {
    if (!landmark) return;

    const unlocked = energy >= Number(landmark?.need || 0);
    if (!unlocked) {
      onShowMessage?.(`需要 ${landmark.need} 点能量才能解锁【${landmark.name}】`);
      return;
    }

    const resource = getLandmarkResource(landmark);

    if (resource?.video) {
      setVideoError(false);
      setPendingVideoLandmark(landmark);
      return;
    }

    applyLandmarkBackground(landmark);
  };

  const finishLandmarkTransition = () => {
    if (!pendingVideoLandmark) return;
    applyLandmarkBackground(pendingVideoLandmark);
    setPendingVideoLandmark(null);
  };

  const handleUnlockEnter = () => {
    if (!state?.ui?.showLandmarkUnlock) return;
    onCloseLandmarkUnlock?.();
    handleLandmarkClick(state.ui.showLandmarkUnlock);
  };

  return (
    <div
      style={{
        ...pageStyle(),
        backgroundImage: `linear-gradient(rgba(235,235,235,0.62), rgba(235,235,235,0.72)), url(${activeBgImage || DEFAULT_BG_IMAGE})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        backgroundRepeat: "no-repeat",
        transition: "background-image 0.35s ease",
        position: "relative",
        minHeight: "100vh",
        overflow: "hidden",
      }}
    >
      {/* 背景增强层：让背景图颜色更饱满，不那么发白 */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(rgba(60,72,92,0.18), rgba(88,64,110,0.14))",
          zIndex: 0,
        }}
      />

      {/* 粒子层：在背景图之上 */}
      <Particles
        id="tsparticles"
        init={particlesInit}
        options={particlesOptions}
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          zIndex: 1,
        }}
      />

      {/* 页面内容层 */}
      <div style={{ position: "relative", zIndex: 2 }}>
        <div style={mainCardStyle()}>
          {/* 给顶部区域的图标添加悬浮放大 className */}
          <HomeTopSection
            dateText={state.app.currentDateText}
            weekdayText={state.app.currentWeekdayText}
            weather={state.app.weather}
            // 传递 className 给子组件内的图标
            iconClassName="hover-scale-icon"
          />

          {/* 地标卡片内的图标/按钮添加悬浮效果 */}
          <LandmarkMapCard
            landmarks={landmarks}
            energy={state.user.energy}
            currentLandmark={currentLandmark}
            onShowMessage={onShowMessage}
            onLandmarkClick={handleLandmarkClick}
            selectedLandmarkId={selectedLandmarkId}
            getLandmarkResource={getLandmarkResource}
            // 传递悬浮样式给地标图标
            landmarkIconStyle={iconHoverStyle}
          />

          <div
            style={{
              background: COLORS.white,
              borderRadius: "18px",
              padding: "1rem",
              marginBottom: "1rem",
              border: `1px solid ${COLORS.line}`,
            }}
          >
            <div style={{ fontWeight: 700, color: COLORS.text }}>每日背词计划</div>
            <div
              style={{
                color: COLORS.subtext,
                fontSize: "0.92rem",
                marginTop: "0.25rem",
                marginBottom: "0.9rem",
              }}
            >
              默认 10 个单词，可自行调整
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
              <input
                type="number"
                min="1"
                max="100"
                value={state.user.dailyPlanCount}
                onChange={(e) => onDailyPlanChange(e.target.value)}
                style={{
                  width: "100%",
                  border: `1px solid ${COLORS.line}`,
                  borderRadius: "12px",
                  padding: "0.8rem",
                  fontSize: "1rem",
                  outline: "none",
                  boxSizing: "border-box",
                }}
              />

              {/* 恢复默认按钮 - 添加悬浮放大 className */}
              <button
                onClick={() => onDailyPlanChange(10)}
                className="hover-scale-btn"
                style={{
                  ...primaryBtnStyle(),
                  ...hoverScaleStyle,
                  width: "100%",
                  padding: "0.8rem 1rem",
                  boxSizing: "border-box",
                  border: "none",
                  borderRadius: "12px",
                  cursor: "pointer",
                  fontSize: "1rem",
                }}
              >
                恢复默认
              </button>
            </div>
          </div>

          {/* 签到卡片内的按钮添加悬浮效果 */}
          <CheckInCard
            streak={state.user.streak}
            showCheckinText={state.ui.showCheckinText}
            onCheckIn={onCheckIn}
            // 传递悬浮样式给签到按钮
            checkinBtnStyle={hoverScaleStyle}
          />

          <InfoMessage message={message} />

          {/* 操作面板按钮添加悬浮放大 */}
          <HomeActionPanel
            onStartLearn={onStartLearn}
            onStartReview={onStartReview}
            // 传递悬浮样式给学习/复习按钮
            btnStyle={hoverScaleStyle}
          />

          {/* 底部导航图标添加悬浮放大 */}
          <HomeBottomNav
            currentScreen={state.ui.screen}
            onGoMyContent={onGoMyContent}
            onGoStatistics={onGoStatistics}
            // 传递悬浮样式给导航图标
            navIconStyle={iconHoverStyle}
          />
        </div>

        <LandmarkUnlockModal
          landmark={state.ui.showLandmarkUnlock}
          onClose={onCloseLandmarkUnlock}
          onEnter={handleUnlockEnter}
          getLandmarkResource={getLandmarkResource}
          // 传递悬浮样式给弹窗按钮
          modalBtnStyle={hoverScaleStyle}
        />

        {pendingVideoLandmark && (
          <div
            style={{
              position: "fixed",
              inset: 0,
              background: "rgba(0,0,0,0.82)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              zIndex: 1001,
              padding: "1rem",
            }}
          >
            <div
              style={{
                width: "100%",
                maxWidth: "760px",
                borderRadius: "18px",
                overflow: "hidden",
                background: "#111",
                boxShadow: "0 18px 50px rgba(0,0,0,0.35)",
              }}
            >
              {!videoError ? (
                <>
                  <video
                    ref={videoRef}
                    src={preloadedVideo || getLandmarkResource(pendingVideoLandmark).video}
                    poster={getLandmarkResource(pendingVideoLandmark).videoPoster}
                    autoPlay
                    playsInline
                    controls
                    preload="auto"
                    onEnded={finishLandmarkTransition}
                    onError={() => setVideoError(true)}
                    style={{
                      width: "100%",
                      display: "block",
                      maxHeight: "72vh",
                      background: "#000",
                    }}
                  />
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "flex-end",
                      gap: "0.75rem",
                      padding: "0.9rem",
                      background: "#111",
                    }}
                  >
                    {/* 关闭按钮 - 添加悬浮放大 className */}
                    <button
                      onClick={() => setPendingVideoLandmark(null)}
                      className="hover-scale-btn"
                      style={{
                        ...hoverScaleStyle,
                        background: "transparent",
                        color: "#fff",
                        border: "1px solid rgba(255,255,255,0.25)",
                        borderRadius: "10px",
                        padding: "0.72rem 1rem",
                        cursor: "pointer",
                      }}
                    >
                      关闭
                    </button>
                    {/* 跳过按钮 - 添加悬浮放大 className */}
                    <button
                      onClick={finishLandmarkTransition}
                      className="hover-scale-btn"
                      style={{
                        ...primaryBtnStyle(),
                        ...hoverScaleStyle,
                        border: "none",
                        borderRadius: "10px",
                        padding: "0.72rem 1rem",
                        cursor: "pointer",
                      }}
                    >
                      跳过并进入
                    </button>
                  </div>
                </>
              ) : (
                <div
                  style={{
                    minHeight: "260px",
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    justifyContent: "center",
                    padding: "2rem",
                    color: "#fff",
                    textAlign: "center",
                    gap: "1rem",
                  }}
                >
                  <div style={{ fontSize: "1.05rem", fontWeight: 700 }}>
                    视频加载失败，仍可直接进入地图
                  </div>
                  {/* 直接进入按钮 - 添加悬浮放大 className */}
                  <button
                    onClick={finishLandmarkTransition}
                    className="hover-scale-btn"
                    style={{
                      ...primaryBtnStyle(),
                      ...hoverScaleStyle,
                      border: "none",
                      borderRadius: "10px",
                      padding: "0.8rem 1rem",
                      cursor: "pointer",
                    }}
                  >
                    直接进入
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}